import React from "react";
import styles from './CourseContent.module.scss';

const CourseContent = (props) => {

  switch(props.courseSelect) {
    case 'select1': courseList = ['1couse', '2course'];
    case 'select2': courseList = ['3couse', '4course'];
    case 'select3': courseList = ['5couse', '6course'];

  }
  return(
    <div className={styles.courseContent}>
      {courseList.map(course => 
        <div ket={course} style={{color: '#fff'}}>{course}</div>
      )}
    </div>
  );
}

export default CourseContent;
